  ('social-worker-moex-07280', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列敘述何者錯誤？', '["概念均發展自經驗", "不是所有概念均有清楚的意義", "變數與屬性均代表概念", "變數是屬性的邏輯群集（logical groupings）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "ce884abe5000", "answer_pdf_sha1": "1468c7a623d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07281', 'social-worker', 'social-worker-moex-101-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列敘述何者錯誤？', '["理論是由一些命題所組成", "理論都具有指明變項間因果關係的功能", "理論對現象的解釋力有層次、形式和模式之別", "新的概念有時也可發揮理論的功用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "ce884abe5000", "answer_pdf_sha1": "1468c7a623d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
